/**
 * Custom mutation hook for updating action page commitments
 *
 * @param options - Configuration options for the mutation
 * @param options.onError - Optional callback for error handling
 * @param options.onSuccess - Optional callback for successful updates
 *
 * @returns A mutation object with the following properties:
 * - mutate: Function to trigger the update
 * - mutateAsync: Async function to trigger the update
 * - isLoading: Boolean indicating if the mutation is in progress
 * - isError: Boolean indicating if the mutation failed
 * - isSuccess: Boolean indicating if the mutation succeeded
 * - error: Error object if the mutation failed
 * - data: Response data if the mutation succeeded
 *
 * @example
 * ```tsx
 * const updateCommitment = useUpdateCommitment({
 *   onSuccess: (data) => {
 *     console.log('Commitment updated:', data);
 *   },
 *   onError: (error) => {
 *     console.error('Failed to update commitment:', error);
 *   },
 * });
 *
 * // Usage
 * updateCommitment.mutate({
 *   commitmentId: 'commitment-123',
 *   t: 'auth-token',
 *   totalAmount: 5000, // $50.00 in cents
 *   donorDetailsAttributes: {
 *     id: 'donor-123',
 *     firstName: 'John',
 *     lastName: 'Doe',
 *     email: 'john@example.com',
 *   },
 * });
 * ```
 */
export const useUpdateCommitment = ({
  onError,
  onSuccess,
}: UseUpdateCommitmentProps = {}) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      commitmentId,
      ...updateData
    }: UpdateActionPagesCommitmentRequest & { commitmentId: string }) => {
      return getApiClient(false, "public").put<ActionPagesCommitmentResponse>(
        `/action_pages_commitments/${commitmentId}`,
        updateData,
      );
    },
    onError: (error: ApiClientError) => {
      onError?.(error);
    },
    onSuccess: async (data, variables) => {
      onSuccess?.(data);

      // Invalidate the commitment query to refetch updated data
      await queryClient.invalidateQueries({
        queryKey: commitmentQueryKeys.entity({
          namespace: "public",
          parameters: {
            commitmentId: variables.commitmentId,
            t: variables.t,
          },
        }).queryKey,
      });
    },
  });
};

